const helmet = require('helmet');
const cors = require('cors');
const rateLimit = require('express-rate-limit');
const morgan = require('morgan');

const app = express();

// Security headers
app.use(helmet());

// Remove server fingerprint
app.disable('x-powered-by');

// Request logging
app.use(morgan('combined'));

// CORS with explicit allowlist
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') || [],
  methods: ['GET'],
}));

// Rate limiting
app.use(rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
}));

// Body parsing with size limits
app.use(express.json({ limit: '100kb' }));

// Routes
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', /* authenticateToken, */ (req, res) => {
  res.json([
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ]);
});

// Global error handler (AFTER routes)
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(500).json({ error: 'Internal Server Error' });
});

const PORT = parseInt(process.env.PORT, 10) || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
```

---

## Priority Action Items

| Priority | Issue | Fix |
|----------|-------|-----|
| 🔴 1 | Missing security headers | Add `helmet()` |
| 🔴 2 | No rate limiting | Add `express-rate-limit` |
| 🟠 3 | Unauthenticated PII exposure | Add auth middleware, strip emails |
| 🟠 4 | Server fingerprinting | `app.disable('x-powered-by')` |
| 🟡 5 | No error handler | Add global error-handling middleware |
| 🟡 6 | No logging | Add `morgan` or structured logger |
| 🟡 7 | Hardcoded port | Use `process.env.PORT` |

