app.use(helmet());       // sets ~15 security headers in one call
app.disable('x-powered-by'); // redundant with helmet, but defense-in-depth
```

---

### 🔴 HIGH — No Rate Limiting (OWASP A04: Insecure Design)

Every endpoint is openly accessible with no throttling, making the server vulnerable to denial-of-service and brute-force attacks.

**Fix — add `express-rate-limit`:**
```js
const rateLimit = require('express-rate-limit');
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);
```

---

### 🔴 HIGH — No Body Parser with Size Limits (OWASP A05: Security Misconfiguration)

The app has no body parsing middleware. When POST/PUT routes are eventually added, forgetting to limit body size enables payload-based DoS.

**Fix — configure body parsers with limits:**
```js
app.use(express.json({ limit: '10kb' }));       // prevent large JSON payloads
app.use(express.urlencoded({ extended: false, limit: '10kb' }));
```

---

### 🟠 MEDIUM — No Input Validation/Sanitization (OWASP A03: Injection)

The `/users` endpoint is static now, but the app has **no validation framework** in place. The moment query parameters or request bodies are introduced, injection risks appear immediately.

**Example of a vulnerable future route (what to avoid):**
```js
// ❌ DANGEROUS — never interpolate user input into queries
app.get('/user', (req, res) => {
  db.query(`SELECT * FROM users WHERE name = '${req.query.name}'`);
});
```

**Fix — set up validation from the start:**
```js
const { query, validationResult } = require('express-validator');

app.get('/users',
  query('name').optional().isAlphanumeric().trim().escape(),
  (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }
    // safe to use req.query.name
  }
);
```

---

### 🟠 MEDIUM — No CORS Configuration (OWASP A05: Security Misconfiguration)

Without explicit CORS rules, the behavior depends on the browser and proxy. This should be explicitly locked down.

**Fix:**
```js
const cors = require('cors');
app.use(cors({
  origin: 'https://yourdomain.com',  // whitelist, never use '*' in production
  methods: ['GET'],
  allowedHeaders: ['Content-Type', 'Authorization'],
}));
```

---

