  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                   // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later' },
});

app.use(limiter);
```

---

### 5. No CORS Configuration (OWASP A05: Security Misconfiguration)

Without explicit CORS, the default behavior depends on how the app is deployed. An attacker's site could potentially make requests to this API.

**Recommendation:**
```js
const cors = require('cors');

